def cavern_props_js():
    """JS snippet: decode + preload all prop images once at shell init."""
    debris = json.dumps(CAVERN_PROPS, separators=(",", ":"))
    rooms = json.dumps(ROOM_PROPS, separators=(",", ":"))
    return (
        '(function(){var D=' + debris + ',R=' + rooms + ';'
        'window._cavernPropImgs={};window._cavernRoomImgs={};var pending=0;'
        'function done(){if(--pending===0&&window._cavernRedrawAll)window._cavernRedrawAll();}'
        'function load(src,dst){for(var g in src){dst[g]=src[g].map(function(b){'
        'var im=new Image();pending++;im.onload=done;im.onerror=done;'
        'im.src="data:image/webp;base64,"+b;return im;});}}'
        'load(D,window._cavernPropImgs);load(R,window._cavernRoomImgs);})();'
    )
